    43	  }
    44	
    45	  /* optional: uE_CapabilityRAT_ContainerList */
    46	  if (cu2du->ue_cap) {
    47	    asn1cCalloc(enc.uE_CapabilityRAT_ContainerList, uE_CapabilityRAT_ContainerList);
