    52	  /* optional: measConfig */
    53	  if (cu2du->meas_config) {
    54	    asn1cCalloc(enc.measConfig, measConfig);
    55	    const byte_array_t *ba = cu2du->meas_config;
    56	    OCTET_STRING_fromBuf(measConfig, (const char *)ba->buf, ba->len);
    57	  }
    58	
    59	  /* optional: HandoverPreparationInformation */
    60	  F1AP_ProtocolExtensionContainer_10696P60_t *p = NULL;
    61	  if (cu2du->ho_prep_info) {
    62	    p = calloc_or_fail(1, sizeof(*p));
    63	    enc.iE_Extensions = (struct F1AP_ProtocolExtensionContainer *)p;
    64	    asn1cSequenceAdd(p->list, F1AP_CUtoDURRCInformation_ExtIEs_t, ie_ext);
    65	    ie_ext->id = F1AP_ProtocolIE_ID_id_HandoverPreparationInformation;
    66	    ie_ext->criticality = F1AP_Criticality_ignore;
    67	    ie_ext->extensionValue.present = F1AP_CUtoDURRCInformation_ExtIEs__extensionValue_PR_HandoverPreparationInformation;
    68	    const byte_array_t *ba = cu2du->ho_prep_info;
    69	    F1AP_HandoverPreparationInformation_t *hpi = &ie_ext->extensionValue.choice.HandoverPreparationInformation;
    70	    OCTET_STRING_fromBuf(hpi, (const char *)ba->buf, ba->len);
    71	  }
    72	
    73	  /* optional: iE_Extensions */
    74	  if (cu2du->meas_timing_config) {
    75	    if (!p)
    76	      p = calloc_or_fail(1, sizeof(*p));
    77	    enc.iE_Extensions = (struct F1AP_ProtocolExtensionContainer *)p;
    78	    asn1cSequenceAdd(p->list, F1AP_CUtoDURRCInformation_ExtIEs_t, ie_ext);
    79	    ie_ext->id = F1AP_ProtocolIE_ID_id_MeasurementTimingConfiguration;
